import express from 'express';
import session from 'express-session';
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dir = dirname(fileURLToPath(import.meta.url));
const CFG   = JSON.parse(readFileSync(join(__dir,'id.json'),'utf-8'));
Object.entries(CFG).forEach(([k,v])=>{process.env[k]=String(v);});

const PANEL_FILE = join(__dir,'panel.json');

export function loadPanel(){
  if(!existsSync(PANEL_FILE))writeFileSync(PANEL_FILE,'{"keys":[]}');
  try{return JSON.parse(readFileSync(PANEL_FILE,'utf-8'));}catch{return{keys:[]};}
}
function savePanel(d){writeFileSync(PANEL_FILE,JSON.stringify(d,null,2));}
export function createKey(label,guildId,ownerId){
  const data=loadPanel();let key;
  do{key=String(Math.floor(10000+Math.random()*90000));}
  while(data.keys.find(k=>k.key===key));
  const entry={key,label:label||'',guildId:guildId||null,ownerId:ownerId||null,createdAt:Date.now(),active:true};
  data.keys.push(entry);savePanel(data);return entry;
}
function deleteKey(key){const d=loadPanel();d.keys=d.keys.filter(k=>k.key!==key);savePanel(d);}
function getKeyData(key){return loadPanel().keys.find(k=>k.key===key&&k.active)||null;}

